<script>

function arSave(ardetails){
	
	var parts = ardetails.split("|");

	var p1 = parts[0];
	var p2 = parts[1];
	var p3 = parts[2];
	
	var d1=$('#'+p1).val();
	if (p2!='filler'){var d2=$('#'+p2).val();}else{var d2='filler';}
	if (p3!='filler'){var d3=$('#'+p3).val();}else{var d3='filler';}
	
	console.log ("P1: "+p1+" - D1: "+d1);
	console.log ("P2: "+p2+" - D2: "+d2);
	console.log ("P3: "+p3+" - D3: "+d3);
	
	$.ajax({
		url: 'AJAX_admin_updatear.php',
		type: 'POST',
		data: {
			'p1': p1,
			'p2': p2,
			'p3': p3,
			'd1': d1,
			'd2': d2,
			'd3': d3
		},
		success: function(response) {

			$('#toastHeader').text('SAVED');
			$('#toastBody').text('Your settings have been saved!');
			$('#toast').toast('show');	
		},
		error: function(jqXHR, textStatus, errorThrown) {
			console.error('Error:', textStatus, ',', errorThrown);
		}
	});

	
}


function connectAr(ar){

	$('#ar'+ar).show();
	$('#connect'+ar).hide();
	$('#close'+ar).show();
	
}

function closeAr(ar){

	$('#ar'+ar).hide();
	$('#connect'+ar).show();
	$('#close'+ar).hide();
	
}		
	$(document).ready(function() {
				
	});

	$('#adminLogout').click(function() {
		$('#logoutModal').modal('show');
	});
	

</script>
